package devmachine

import (
	"net/http"

	devmachinemodel "tap-edu-backend/internal/model/devmachine"
	devmachineservice "tap-edu-backend/internal/service/devmachine"
	"tap-edu-backend/pkg/external/k8s"

	"github.com/gin-gonic/gin"
	"go.uber.org/zap"
)

type Handler struct {
	service devmachineservice.Service
	logger  *zap.Logger
}

func NewHandler(service devmachineservice.Service, logger *zap.Logger) *Handler {
	return &Handler{
		service: service,
		logger:  logger,
	}
}

// CreatePod 创建 Pod
func (h *Handler) CreatePod(c *gin.Context) {
	var req devmachinemodel.CreatePodRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	podSpec := &k8s.PodSpec{
		Name:    req.Name,
		Image:   req.Image,
		Command: req.Command,
		Args:    req.Args,
		Env:     req.Env,
		Labels:  req.Labels,
	}

	if req.Resources != nil {
		podSpec.Resources = &k8s.ResourceRequirements{
			CPURequest:    req.Resources.CPURequest,
			CPULimit:      req.Resources.CPULimit,
			MemoryRequest: req.Resources.MemoryRequest,
			MemoryLimit:   req.Resources.MemoryLimit,
		}
	}

	if err := h.service.CreatePod(c.Request.Context(), podSpec); err != nil {
		h.logger.Error("failed to create pod", zap.Error(err), zap.String("name", req.Name))
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, devmachinemodel.CreatePodResponse{Message: "pod created successfully"})
}

// DeletePod 删除 Pod
func (h *Handler) DeletePod(c *gin.Context) {
	var req devmachinemodel.DeletePodRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if err := h.service.DeletePod(c.Request.Context(), req.Name); err != nil {
		h.logger.Error("failed to delete pod", zap.Error(err), zap.String("name", req.Name))
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "pod deleted successfully"})
}

// GetPod 获取 Pod 信息
func (h *Handler) GetPod(c *gin.Context) {
