package k8s

import (
	"context"
)

// DevMachinePhase represents the current lifecycle phase of the dev machine pod
type DevMachinePhase string

const (
	// DevMachinePhaseScheduling means the pod is waiting to be assigned to a node
	DevMachinePhaseScheduling DevMachinePhase = "Scheduling"
	// DevMachinePhaseImagePulling means container images are being pulled (or failed to pull)
	DevMachinePhaseImagePulling DevMachinePhase = "ImagePulling"
	// DevMachinePhaseInitializing means init containers are running
	DevMachinePhaseInitializing DevMachinePhase = "Initializing"
	// DevMachinePhaseStarting means main containers are starting but not yet ready
	DevMachinePhaseStarting DevMachinePhase = "Starting"
	// DevMachinePhaseRunning means all containers are running and ready
	DevMachinePhaseRunning DevMachinePhase = "Running"
	// DevMachinePhaseError means the pod has encountered an unrecoverable error
	DevMachinePhaseError DevMachinePhase = "Error"
	// DevMachinePhaseTerminating means the pod is being deleted
	DevMachinePhaseTerminating DevMachinePhase = "Terminating"
	// DevMachinePhaseUnknown means the pod state cannot be determined
	DevMachinePhaseUnknown DevMachinePhase = "Unknown"
)

// ContainerStatusInfo holds the status of a single container (init or main)
type ContainerStatusInfo struct {
	Name     string `json:"name"`
	IsInit   bool   `json:"is_init"`
	State    string `json:"state"`            // waiting / running / terminated
	Reason   string `json:"reason,omitempty"` // e.g. CrashLoopBackOff, OOMKilled
	Message  string `json:"message,omitempty"`
	Ready    bool   `json:"ready"`
	Restarts int32  `json:"restarts"`
}

// Client Kubernetes 客户端接口
type Client interface {
	// CreatePod 创建 Pod
	CreatePod(ctx context.Context, pod *PodSpec) error
	// DeletePod 删除 Pod
	DeletePod(ctx context.Context, name string) error
	// GetPod 获取 Pod 信息
	GetPod(ctx context.Context, name string) (*PodInfo, error)
	// ListPods 列出 Pod
	ListPods(ctx context.Context, labels map[string]string) ([]PodInfo, error)
	// GetPodLogs 获取 Pod 日志
	GetPodLogs(ctx context.Context, name string, tailLines int64) (string, error)
}

type PodSpec struct {
	Name      string
	Image     string
	Command   []string
	Args      []string
	Env       map[string]string
	Resources *ResourceRequirements
	Labels    map[string]string
}

type ResourceRequirements struct {
	CPURequest    string
	CPULimit      string
	MemoryRequest string
	MemoryLimit   string
}

// PodInfo holds the detailed status of a pod
type PodInfo struct {
	Name       string
	Phase      DevMachinePhase
	IsReady    bool
	Reason     string // populated when Phase is Error or Scheduling failure
	Message    string
	Containers []ContainerStatusInfo
	Image      string
	CreatedAt  string
	Labels     map[string]string
}

