+// podToInfo converts a Kubernetes Pod object into PodInfo with a derived lifecycle phase.
+func podToInfo(pod *corev1.Pod) *PodInfo {
+	image := ""
+	if len(pod.Spec.Containers) > 0 {
+		image = pod.Spec.Containers[0].Image
+	}
+
+	phase, reason, message := deriveDevMachinePhase(pod)
+
+	return &PodInfo{
+		Name:       pod.Name,
+		Phase:      phase,
+		IsReady:    isPodReady(pod),
+		Reason:     reason,
+		Message:    message,
+		Containers: buildContainerStatuses(pod),
+		Image:      image,
+		CreatedAt:  pod.CreationTimestamp.Format("2006-01-02 15:04:05"),
+		Labels:     pod.Labels,
+	}
+}
+
+// deriveDevMachinePhase maps the raw Kubernetes pod state to a DevMachinePhase.
+// It returns the phase together with a reason and message describing any problem.
+func deriveDevMachinePhase(pod *corev1.Pod) (phase DevMachinePhase, reason, message string) {
+	// Being deleted
+	if pod.DeletionTimestamp != nil {
+		return DevMachinePhaseTerminating, "", ""
+	}
+
+	switch pod.Status.Phase {
+	case corev1.PodFailed:
+		return DevMachinePhaseError, pod.Status.Reason, pod.Status.Message
+	case corev1.PodSucceeded:
+		// Treat a cleanly exited pod as still "running" from a UX perspective;
+		// callers can inspect IsReady for finer-grained checks.
+		return DevMachinePhaseRunning, "", ""
+	case corev1.PodUnknown:
+		return DevMachinePhaseUnknown, "", ""
+	}
+
+	// Check whether the pod has been scheduled yet.
+	scheduledToNode := false
+	for _, cond := range pod.Status.Conditions {
+		if cond.Type == corev1.PodScheduled {
+			if cond.Status == corev1.ConditionFalse {
+				// Scheduling is blocked (e.g. insufficient resources, taints).
+				return DevMachinePhaseScheduling, cond.Reason, cond.Message
+			}
+			scheduledToNode = true
+		}
+	}
+	if !scheduledToNode {
+		return DevMachinePhaseScheduling, "", ""
+	}
+
+	// Inspect init containers (checked in order; the first non-ready one wins).
+	for _, cs := range pod.Status.InitContainerStatuses {
+		if cs.State.Waiting != nil {
+			r := cs.State.Waiting.Reason
+			switch r {
+			case "ErrImagePull", "ImagePullBackOff":
+				return DevMachinePhaseImagePulling, r, cs.State.Waiting.Message
+			case "PodInitializing", "":
+				return DevMachinePhaseInitializing, "", ""
+			default:
+				return DevMachinePhaseError, r, cs.State.Waiting.Message
+			}
+		}
+		if cs.State.Terminated != nil && cs.State.Terminated.ExitCode != 0 {
+			return DevMachinePhaseError, cs.State.Terminated.Reason, cs.State.Terminated.Message
+		}
+	}
+	// Some init containers may not have a status entry yet.
+	if len(pod.Spec.InitContainers) > len(pod.Status.InitContainerStatuses) {
+		return DevMachinePhaseInitializing, "", ""
+	}
+	// All init containers reported, but not all ready → still initializing.
+	for _, cs := range pod.Status.InitContainerStatuses {
+		if !cs.Ready {
+			return DevMachinePhaseInitializing, "", ""
+		}
+	}
+
+	// Inspect main containers.
+	for _, cs := range pod.Status.ContainerStatuses {
+		if cs.State.Waiting != nil {
+			r := cs.State.Waiting.Reason
+			switch r {
+			case "ErrImagePull", "ImagePullBackOff":
+				return DevMachinePhaseImagePulling, r, cs.State.Waiting.Message
+			case "CrashLoopBackOff":
+				return DevMachinePhaseError, r, cs.State.Waiting.Message
+			case "ContainerCreating", "":
+				return DevMachinePhaseStarting, "", ""
+			default:
+				return DevMachinePhaseError, r, cs.State.Waiting.Message
+			}
+		}
+		if cs.State.Terminated != nil && cs.State.Terminated.ExitCode != 0 {
+			return DevMachinePhaseError, cs.State.Terminated.Reason, cs.State.Terminated.Message
+		}
+	}
+
+	if len(pod.Status.ContainerStatuses) == 0 {
+		return DevMachinePhaseStarting, "", ""
+	}
+
+	// All containers must be ready for the pod to be considered Running.
+	for _, cs := range pod.Status.ContainerStatuses {
+		if !cs.Ready {
+			return DevMachinePhaseStarting, "", ""
+		}
+	}
+
+	return DevMachinePhaseRunning, "", ""
+}
+
+// isPodReady returns true when the pod's Ready condition is True.
+func isPodReady(pod *corev1.Pod) bool {
+	for _, cond := range pod.Status.Conditions {
+		if cond.Type == corev1.PodReady {
+			return cond.Status == corev1.ConditionTrue
+		}
+	}
+	return false
+}
+
+// buildContainerStatuses collects status info for all init and main containers.
+func buildContainerStatuses(pod *corev1.Pod) []ContainerStatusInfo {
+	var statuses []ContainerStatusInfo
+
+	for _, cs := range pod.Status.InitContainerStatuses {
+		statuses = append(statuses, containerStatusInfo(cs, true))
+	}
+	for _, cs := range pod.Status.ContainerStatuses {
+		statuses = append(statuses, containerStatusInfo(cs, false))
+	}
+	return statuses
+}
+
+func containerStatusInfo(cs corev1.ContainerStatus, isInit bool) ContainerStatusInfo {
+	info := ContainerStatusInfo{
+		Name:     cs.Name,
+		IsInit:   isInit,
+		Ready:    cs.Ready,
+		Restarts: cs.RestartCount,
+	}
+	switch {
+	case cs.State.Running != nil:
+		info.State = "running"
+	case cs.State.Waiting != nil:
+		info.State = "waiting"
+		info.Reason = cs.State.Waiting.Reason
+		info.Message = cs.State.Waiting.Message
+	case cs.State.Terminated != nil:
+		info.State = "terminated"
+		info.Reason = cs.State.Terminated.Reason
+		info.Message = cs.State.Terminated.Message
+	default:
+		info.State = "waiting"
+	}
+	return info
+}
